using System.Collections;
using UnityEngine;

/// <summary>Recurso de PlayerProgress que Action_GiveResource pode dar (ou tirar, com amount negativo).</summary>
public enum PlayerResourceType
{
    Sementes,
    RunasDeGaia,
    BrotosDeVida,
    FragmentosVitais,

    /// <summary>Ecos Perdidos — moeda para comprar Sussurros da Terra no Contador de Histórias.</summary>
    EcosPerdidos,
}

/// <summary>
/// Dá (ou tira, com "amount" negativo) uma quantidade de um recurso de
/// PlayerProgress. PlayerProgress já garante que o total nunca fica negativo.
/// </summary>
[System.Serializable]
public class Action_GiveResource : NpcAction
{
    public PlayerResourceType resource = PlayerResourceType.Sementes;

    [Tooltip("Quantidade a dar. Usa um valor negativo para tirar recursos.")]
    public int amount = 1;

    public override IEnumerator Execute(NpcController npc)
    {
        var progress = PlayerProgress.Instance;
        if (progress == null) yield break;

        switch (resource)
        {
            case PlayerResourceType.Sementes:
                progress.GiveSementes(amount);
                break;

            case PlayerResourceType.RunasDeGaia:
                progress.GiveRunasDeGaia(amount);
                break;

            case PlayerResourceType.BrotosDeVida:
                progress.GiveBrotosDeVida(amount);
                break;

            case PlayerResourceType.FragmentosVitais:
                progress.GiveFragmentosVitais(amount);
                break;

            case PlayerResourceType.EcosPerdidos:
                progress.GiveEcosPerdidos(amount);
                break;
        }

        yield break;
    }
}

/// <summary>Dá um item ao inventário do player e, opcionalmente, equipa-o de imediato.</summary>
[System.Serializable]
public class Action_GiveItem : NpcAction
{
    public ItemData item;

    [Tooltip("Se activo, o item passa também a ser o item equipado (equippedItemId).")]
    public bool equip;

    public override IEnumerator Execute(NpcController npc)
    {
        var progress = PlayerProgress.Instance;
        if (progress == null || item == null) yield break;

        progress.GiveItem(item);
        if (equip) progress.EquipItem(item);

        yield break;
    }
}

/// <summary>
/// Desbloqueia um upgrade permanente (ex: dash extra, mais corações). Se for
/// um Instinto (UpgradeData.toggleable), usa UnlockUpgradeEnabled para que
/// fique LIGADO por defeito ao ser desbloqueado — consistente com
/// Action_BuyUpgrade e com o comentário do próprio sistema em
/// PlayerProgress.UnlockUpgradeEnabled (Instintos desbloqueados começam ON).
/// </summary>
[System.Serializable]
public class Action_UnlockUpgrade : NpcAction
{
    public UpgradeData upgrade;

    public override IEnumerator Execute(NpcController npc)
    {
        var progress = PlayerProgress.Instance;
        if (progress == null || upgrade == null) yield break;

        progress.UnlockUpgradeEnabled(upgrade);
        yield break;
    }
}

/// <summary>
/// Compra um upgrade (Tarefa #20 — Economia): gasta
/// <see cref="UpgradeData.unlockCost"/> de <see cref="UpgradeData.unlockCurrency"/>
/// e desbloqueia o upgrade (se for um Instinto, já fica ligado por defeito —
/// ver PlayerProgress.UnlockUpgradeEnabled). Se o jogador já tiver o upgrade
/// ou não tiver saldo suficiente, não faz nada — usar
/// <see cref="Condition_CanAffordUpgrade"/> num "+ Adicionar Condição" antes
/// desta acção para mostrar um ramo de diálogo "sem sementes suficientes" /
/// "já tens este upgrade".
/// </summary>
[System.Serializable]
public class Action_BuyUpgrade : NpcAction
{
    public UpgradeData upgrade;

    public override IEnumerator Execute(NpcController npc)
    {
        var progress = PlayerProgress.Instance;
        if (progress == null || upgrade == null) yield break;
        if (progress.HasUpgrade(upgrade)) yield break;

        if (progress.TrySpendResource(upgrade.unlockCurrency, upgrade.unlockCost))
            progress.UnlockUpgradeEnabled(upgrade);

        yield break;
    }
}

/// <summary>
/// Liberta um animal (regista em PlayerProgress.freedAnimalIds) e, por
/// omissão, desbloqueia a forma no FormSwitcher do player para que ela passe
/// a estar disponível na roda de transformação.
/// </summary>
[System.Serializable]
public class Action_FreeAnimal : NpcAction
{
    public AnimalFormData form;

    [Tooltip("Se activo, também adiciona a forma a FormSwitcher.unlockedForms (necessário para o player conseguir transformar-se nela). Desactiva apenas se quiseres registar o animal como \"libertado\" sem o tornar jogável de imediato.")]
    public bool unlockForSwitching = true;

    public override IEnumerator Execute(NpcController npc)
    {
        if (form == null) yield break;

        PlayerProgress.Instance?.FreeAnimal(form);

        if (unlockForSwitching && npc.Player != null)
        {
            var switcher = npc.Player.GetComponent<FormSwitcher>();
            switcher?.UnlockForm(form);
        }

        yield break;
    }
}

/// <summary>Marca uma área como visitada (PlayerProgress.MarkVisited).</summary>
[System.Serializable]
public class Action_MarkAreaVisited : NpcAction
{
    public AreaData area;

    public override IEnumerator Execute(NpcController npc)
    {
        if (area != null) PlayerProgress.Instance?.MarkVisited(area);
        yield break;
    }
}

/// <summary>
/// Regista a entrega de um Sussurro da Terra a este NPC
/// (PlayerProgress.AddWhisperDelivered) — usar num evento de diálogo onde o
/// jogador entrega/conta um Sussurro previamente recolhido
/// (SussurroDaTerraPickup só regista "encontrado"; a entrega é um passo
/// separado feito aqui).
/// </summary>
[System.Serializable]
public class Action_DeliverWhisper : NpcAction
{
    public AreaData area;

    public override IEnumerator Execute(NpcController npc)
    {
        if (area != null) PlayerProgress.Instance?.AddWhisperDelivered(area);
        yield break;
    }
}

/// <summary>
/// Força um autosave imediato (SaveManager.SaveAutosave) — usar no fim de
/// eventos de NPC que alteram progresso de forma irreversível (libertar um
/// animal, resgatar um NPC, desbloquear uma forma/upgrade importante, etc.).
/// Sem isto, esse progresso só fica gravado na próxima mudança de área,
/// checkpoint ou save manual — alguns "pickups importantes" já chamam
/// SaveAutosave directamente (ex: CameraAreaBounds ao mudar de área), mas as
/// acções de NPC não tinham forma equivalente.
/// </summary>
[System.Serializable]
public class Action_Autosave : NpcAction
{
    public override IEnumerator Execute(NpcController npc)
    {
        SaveManager.Instance?.SaveAutosave();
        yield break;
    }
}

/// <summary>
/// Marca o boss de um mundo como derrotado. Isto também activa
/// "IsReturningAfterBoss" para esse mundo, até Action_ClearReturningAfterBoss
/// ser chamada (normalmente no evento de "regresso pós-boss" desse NPC).
/// </summary>
[System.Serializable]
public class Action_SetBossDefeated : NpcAction
{
    public WorldData world;

    public override IEnumerator Execute(NpcController npc)
    {
        if (world != null) PlayerProgress.Instance?.SetBossDefeated(world);
        yield break;
    }
}

/// <summary>
/// Limpa a flag "regresso pós-boss" de um mundo — usar no fim do evento de
/// "regresso" que reage à derrota do boss, para não disparar de novo.
/// </summary>
[System.Serializable]
public class Action_ClearReturningAfterBoss : NpcAction
{
    public WorldData world;

    public override IEnumerator Execute(NpcController npc)
    {
        if (world != null) PlayerProgress.Instance?.ClearReturningAfterBoss(world);
        yield break;
    }
}

/// <summary>
/// Activa ou desactiva o Modo Difícil ("Juramento Difícil") ligando/desligando
/// directamente o Instinto correspondente em enabledUpgradeIds — a mesma fonte
/// de verdade usada por <see cref="PlayerProgress.IsHardModeActive"/>,
/// PlayerCombat e PlayerHealthRegen.
/// </summary>
[System.Serializable]
public class Action_SetHardMode : NpcAction
{
    public bool hardMode = true;

    public override IEnumerator Execute(NpcController npc)
    {
        var progress = PlayerProgress.Instance;
        if (progress != null) progress.SetUpgradeEnabled(PlayerProgress.JuramentoDificilUpgradeId, hardMode);

        yield break;
    }
}

/// <summary>
/// Activa (ou desactiva) a Recompensa de Pós-Jogo (GDD): a partir daqui o
/// FormSwitcher passa a ter cooldown de transformação zero e permite
/// transformar em qualquer lugar, incluindo no ar — mantendo as regras de
/// formas aquáticas/terrestres (ver FormSwitcher.CanSwitchTo). Persistido via
/// enabledUpgradeIds, mesmo mecanismo de Action_SetHardMode. Usar numa
/// cutscene/evento de fim de jogo.
/// </summary>
[System.Serializable]
public class Action_SetPostGameRewardActive : NpcAction
{
    public bool active = true;

    public override IEnumerator Execute(NpcController npc)
    {
        var progress = PlayerProgress.Instance;
        if (progress != null) progress.SetUpgradeEnabled(PlayerProgress.RecompensaPosJogoUpgradeId, active);

        yield break;
    }
}
